CREATE TABLE `empresas` (
  `id_empresa` int NOT NULL,
  `id_tipo_empresa` int NOT NULL,
  `tipo_auditoria` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rfc` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `giro` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `direccion` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ciudad` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pais` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `contacto_nombre` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contacto_correo` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contacto_telefono` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `activo` tinyint(1) NOT NULL,
