  CONSTRAINT `fk_empresas_tipos_empresa` FOREIGN KEY (`id_tipo_empresa`) REFERENCES `tipos_empresa` (`id_tipo_empresa`) ON DELETE RESTRICT ON UPDATE CASCADE
