UNLOCK TABLES;
DROP TABLE IF EXISTS `auditorias`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `auditorias` (
  `id_auditoria` int NOT NULL,
  `id_empresa_auditora` int NOT NULL,
  `id_cliente` int NOT NULL,
  `id_solicitud_pago` int NOT NULL,
  `id_estado` int NOT NULL,
  `monto` decimal(12,2) NOT NULL,
  `creada_en` datetime NOT NULL,
  `objetivo` text COLLATE utf8mb4_unicode_ci,
  `estado_actualizado_en` datetime DEFAULT NULL,
  `fecha_inicio` date DEFAULT NULL,
  PRIMARY KEY (`id_auditoria`),
  KEY `idx_auditorias_auditora` (`id_empresa_auditora`),
  KEY `idx_auditorias_cliente` (`id_cliente`),
  KEY `idx_auditorias_solicitud` (`id_solicitud_pago`),
  KEY `idx_auditorias_estado` (`id_estado`),
  CONSTRAINT `fk_auditorias_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `usuarios` (`id_usuario`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_auditorias_empresas_auditora` FOREIGN KEY (`id_empresa_auditora`) REFERENCES `empresas` (`id_empresa`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_auditorias_estado` FOREIGN KEY (`id_estado`) REFERENCES `estados_auditoria` (`id_estado`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_auditorias_solicitud` FOREIGN KEY (`id_solicitud_pago`) REFERENCES `solicitudes_pago` (`id_solicitud`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
