CREATE TABLE `solicitudes_pago` (
  `id_solicitud` int NOT NULL,
  `id_empresa` int NOT NULL,
  `id_empresa_auditora` int NOT NULL,
  `id_empresa_cliente` int DEFAULT NULL,
  `id_cliente` int NOT NULL,
  `monto` decimal(12,2) NOT NULL,
  `concepto` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `id_estado` int NOT NULL,
  `creado_en` datetime NOT NULL,
  `creado_por_supervisor` int DEFAULT NULL,
  `creado_por_auditor` int DEFAULT NULL,
  `pagada_en` datetime DEFAULT NULL,
  `paypal_order_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id_solicitud`),
  KEY `idx_solicitudes_empresa_auditora` (`id_empresa_auditora`),
  KEY `idx_solicitudes_empresa_cliente` (`id_empresa_cliente`),
  KEY `idx_solicitudes_cliente` (`id_cliente`),
  KEY `idx_solicitudes_estado` (`id_estado`),
  KEY `fk_solicitudes_empresas_owner` (`id_empresa`),
  KEY `fk_solicitudes_creado_supervisor` (`creado_por_supervisor`),
  KEY `fk_solicitudes_creado_auditor` (`creado_por_auditor`),
  CONSTRAINT `fk_solicitudes_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `usuarios` (`id_usuario`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_creado_auditor` FOREIGN KEY (`creado_por_auditor`) REFERENCES `usuarios` (`id_usuario`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_creado_supervisor` FOREIGN KEY (`creado_por_supervisor`) REFERENCES `usuarios` (`id_usuario`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_empresas_auditora` FOREIGN KEY (`id_empresa_auditora`) REFERENCES `empresas` (`id_empresa`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_empresas_cliente` FOREIGN KEY (`id_empresa_cliente`) REFERENCES `empresas` (`id_empresa`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_empresas_owner` FOREIGN KEY (`id_empresa`) REFERENCES `empresas` (`id_empresa`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_solicitudes_estado` FOREIGN KEY (`id_estado`) REFERENCES `estados_solicitud_pago` (`id_estado`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
