UNLOCK TABLES;
DROP TABLE IF EXISTS `evidencias`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `evidencias` (
  `id_evidencia` int NOT NULL,
  `id_auditoria` int NOT NULL,
  `id_modulo` int NOT NULL,
  `id_auditor` int NOT NULL,
  `tipo` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `descripcion` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre_archivo` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `url_archivo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `creado_en` datetime NOT NULL,
  `actualizado_en` datetime DEFAULT NULL,
  PRIMARY KEY (`id_evidencia`),
  KEY `idx_evidencias_auditoria` (`id_auditoria`),
  KEY `idx_evidencias_modulo` (`id_modulo`),
  KEY `idx_evidencias_auditor` (`id_auditor`),
  CONSTRAINT `fk_evidencias_auditor` FOREIGN KEY (`id_auditor`) REFERENCES `usuarios` (`id_usuario`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_evidencias_auditoria` FOREIGN KEY (`id_auditoria`) REFERENCES `auditorias` (`id_auditoria`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_evidencias_modulo` FOREIGN KEY (`id_modulo`) REFERENCES `modulos_ambientales` (`id_modulo`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `evidencias` WRITE;
