UNLOCK TABLES;
DROP TABLE IF EXISTS `conversaciones`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `conversaciones` (
  `id_conversacion` int NOT NULL,
  `id_cliente` int NOT NULL,
  `id_empresa_auditora` int NOT NULL,
  `asunto` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `creado_en` datetime NOT NULL,
  `ultimo_mensaje_fecha` datetime DEFAULT NULL,
  `activo` tinyint(1) NOT NULL,
  PRIMARY KEY (`id_conversacion`),
  KEY `idx_conv_cliente` (`id_cliente`),
  KEY `idx_conv_empresa_auditora` (`id_empresa_auditora`),
  CONSTRAINT `fk_conv_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `usuarios` (`id_usuario`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_conv_empresa_auditora` FOREIGN KEY (`id_empresa_auditora`) REFERENCES `empresas` (`id_empresa`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `conversaciones` WRITE;
