CREATE TABLE `notificaciones` (
  `id_notificacion` int NOT NULL,
  `id_cliente` int NOT NULL,
  `id_auditoria` int DEFAULT NULL,
  `tipo` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `titulo` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `mensaje` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `fecha` datetime NOT NULL,
  `leida` tinyint(1) NOT NULL,
  PRIMARY KEY (`id_notificacion`),
  KEY `idx_notif_cliente` (`id_cliente`),
  KEY `idx_notif_auditoria` (`id_auditoria`),
  KEY `idx_notif_fecha` (`fecha`),
  CONSTRAINT `fk_notif_auditoria` FOREIGN KEY (`id_auditoria`) REFERENCES `auditorias` (`id_auditoria`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_notif_cliente` FOREIGN KEY (`id_cliente`) REFERENCES `usuarios` (`id_usuario`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
